import{_ as s,o as e,c as r,ak as n}from"./chunks/framework.CDHwDzB5.js";const m=JSON.parse('{"title":"支持的下载协议","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/supported-protocols.md","filePath":"zh/guide/supported-protocols.md","lastUpdated":1772513262000}'),a={name:"zh/guide/supported-protocols.md"};function o(i,t,l,p,g,d){return e(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="支持的下载协议" tabindex="-1">支持的下载协议 <a class="header-anchor" href="#支持的下载协议" aria-label="Permalink to “支持的下载协议”">​</a></h1><p>TTHSD Next 内置了灵活的协议路由工厂 (<em><strong>get_downloader</strong></em>)，根据 URL 自动选择最优的下载器实现。目前原生支持以下 <strong>7 种下载协议</strong>：</p><h2 id="http-https" tabindex="-1">HTTP / HTTPS <a class="header-anchor" href="#http-https" aria-label="Permalink to “HTTP / HTTPS”">​</a></h2><p><strong>源码模块</strong>: <em><strong>http_downloader.rs</strong></em></p><p>标准的 HTTP/HTTPS 协议下载，是最常用的下载方式。</p><p><strong>核心特性：</strong></p><ul><li><strong>动态工作量窃取分片</strong>：当一个分片完成后，自动从剩余工作量最大的分片中窃取后半部分继续下载，最大化带宽利用率</li><li><strong>TLS 指纹伪装</strong>：模拟 Chrome 133 的 TLS/JA3/HTTP2 指纹，绕过 Cloudflare 等反爬机制</li><li><strong>全局连接池</strong>：所有下载器实例共享统一的 HTTP 客户端，减少 TLS 握手开销</li><li><strong>停滞检测</strong>：30 秒无数据自动重连</li><li><strong>最大并发</strong>：单文件最多 64 个并发连接</li></ul><p><strong>URL 格式：</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://example.com/file.zip</span></span>
<span class="line"><span>http://example.com/file.zip</span></span></code></pre></div><hr><h2 id="http-3-quic" tabindex="-1">HTTP/3 (QUIC) <a class="header-anchor" href="#http-3-quic" aria-label="Permalink to “HTTP/3 (QUIC)”">​</a></h2><p><strong>源码模块</strong>: <em><strong>http3_downloader.rs</strong></em></p><p>基于 QUIC 协议的 HTTP/3 下载，通过 UDP 传输提速。</p><p><strong>核心特性：</strong></p><ul><li><strong>自动探测</strong>：下载前发送 HEAD 请求（800ms 超时），检查服务端 <em><strong>Alt-Svc: h3</strong></em> 响应头</li><li><strong>无缝降级</strong>：如果服务器不支持 HTTP/3，自动回退到 HTTP/HTTPS</li><li><strong>QUIC 协议栈</strong>：使用 <em><strong>quinn</strong></em> + <em><strong>h3</strong></em> 构建完整的 QUIC/HTTP3 协议栈</li></ul><p><strong>触发条件：</strong></p><ul><li>URL 以 <em><strong>https://</strong></em> 开头且服务器返回 <em><strong>Alt-Svc</strong></em> 包含 <em><strong>h3</strong></em></li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>如 Cloudflare、Google 等 CDN 通常支持 HTTP/3，下载这类资源时会自动启用。</p></div><hr><h2 id="ftp" tabindex="-1">FTP <a class="header-anchor" href="#ftp" aria-label="Permalink to “FTP”">​</a></h2><p><strong>源码模块</strong>: <em><strong>ftp_downloader.rs</strong></em></p><p>标准 FTP 文件传输协议。</p><p><strong>核心特性：</strong></p><ul><li>支持匿名登录和密码认证</li><li>二进制传输模式</li><li>64KB 读取缓冲</li></ul><p><strong>URL 格式：</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ftp://ftp.example.com/path/to/file.zip</span></span>
<span class="line"><span>ftp://user:password@ftp.example.com/path/to/file.zip</span></span></code></pre></div><hr><h2 id="sftp-ssh" tabindex="-1">SFTP (SSH) <a class="header-anchor" href="#sftp-ssh" aria-label="Permalink to “SFTP (SSH)”">​</a></h2><p><strong>源码模块</strong>: <em><strong>sftp_downloader.rs</strong></em></p><p>基于 SSH 隧道的安全文件传输协议，通过 <em><strong>russh</strong></em> 和 <em><strong>russh-sftp</strong></em> 实现纯 Rust 异步连接。</p><p><strong>核心特性：</strong></p><ul><li>密码认证和密钥认证</li><li>自动流式传输（无需暂存完整文件到内存）</li><li>进度回调集成（实时字节数统计）</li><li>性能监控集成</li></ul><p><strong>URL 格式：</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>sftp://user:password@host/path/to/file</span></span>
<span class="line"><span>sftp://user:password@host:2222/path/to/file</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>SFTP 与 FTP/FTPS 是完全不同的协议。SFTP 基于 SSH 隧道加密传输，安全性更高。</p></div><hr><h2 id="bittorrent-magnet" tabindex="-1">BitTorrent / Magnet <a class="header-anchor" href="#bittorrent-magnet" aria-label="Permalink to “BitTorrent / Magnet”">​</a></h2><p><strong>源码模块</strong>: <em><strong>torrent_downloader.rs</strong></em></p><p>基于 <em><strong>librqbit</strong></em>（纯 Rust BitTorrent 客户端）的种子下载。</p><p><strong>核心特性：</strong></p><ul><li>支持磁力链接 (<em><strong>magnet:</strong></em>) 和 <em><strong>.torrent</strong></em> 文件 URL</li><li>完整的 DHT 网络支持</li><li>PEX (Peer Exchange) 节点发现</li><li>1 秒轮询进度更新</li></ul><p><strong>URL 格式：</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>magnet:?xt=urn:btih:\\&lt;hash\\&gt;&amp;dn=\\&lt;name\\&gt;</span></span>
<span class="line"><span>https://example.com/file.torrent</span></span></code></pre></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>BT 下载需要 DHT 网络预热，通常 30-60 秒后才开始接收到 Peer 数据。</p></div><hr><h2 id="ed2k-emule" tabindex="-1">ED2K (eMule) <a class="header-anchor" href="#ed2k-emule" aria-label="Permalink to “ED2K (eMule)”">​</a></h2><p><strong>源码模块</strong>: <em><strong>ed2k_downloader.rs</strong></em></p><p>eDonkey2000 协议链接的下载，无需安装传统电驴客户端。</p><p><strong>核心特性：</strong></p><ul><li>解析标准 <em><strong>ed2k://</strong></em> URL 格式</li><li>通过 HTTP 网关 (<code>https://ed2k.lyoko.io/hash/&lt;hash&gt;</code>) 转换为 HTTP 下载</li><li>自动文件名 percent-decode</li></ul><p><strong>URL 格式：</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ed2k://|file|\\&lt;文件名\\&gt;|\\&lt;大小\\&gt;|\\&lt;Hash\\&gt;|/</span></span></code></pre></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>ED2K 下载依赖第三方 HTTP 网关服务 <em><strong>ed2k.lyoko.io</strong></em>，其可用性取决于该服务的运行状态。</p></div><hr><h2 id="metalink-4-0" tabindex="-1">Metalink 4.0 <a class="header-anchor" href="#metalink-4-0" aria-label="Permalink to “Metalink 4.0”">​</a></h2><p><strong>源码模块</strong>: <em><strong>metalink_downloader.rs</strong></em></p><p>Metalink (<em><strong>.meta4</strong></em> / <em><strong>.metalink</strong></em>) 是一种 XML 元数据格式，包含多个镜像 URL 及其优先级。</p><p><strong>核心特性：</strong></p><ul><li>解析 Metalink 4.0 XML 文件</li><li>按 <em><strong>priority</strong></em> 字段排序，自动选择最优 HTTP/HTTPS 镜像</li><li>流式下载所选镜像</li></ul><p><strong>URL 格式：</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://example.com/file.meta4</span></span>
<span class="line"><span>https://example.com/file.metalink</span></span></code></pre></div><hr><h2 id="协议路由逻辑" tabindex="-1">协议路由逻辑 <a class="header-anchor" href="#协议路由逻辑" aria-label="Permalink to “协议路由逻辑”">​</a></h2><p>下载器的协议选择由 <em><strong>get_downloader()</strong></em> 工厂函数自动完成：</p><table tabindex="0"><thead><tr><th>URL 特征</th><th>路由到</th></tr></thead><tbody><tr><td><em><strong>http://</strong></em> 或 <em><strong>https://</strong></em></td><td>HTTPDownloader 或 HTTP3Downloader（自动探测）</td></tr><tr><td><em><strong>ftp://</strong></em> 或 <em><strong>ftps://</strong></em></td><td>FTPDownloader</td></tr><tr><td><em><strong>sftp://</strong></em></td><td>SFTPDownloader</td></tr><tr><td><em><strong>magnet:</strong></em> 或 URL 以 <em><strong>.torrent</strong></em> 结尾</td><td>TorrentDownloader</td></tr><tr><td><em><strong>ed2k://</strong></em></td><td>ED2KDownloader</td></tr><tr><td>URL 以 <em><strong>.metalink</strong></em> 或 <em><strong>.meta4</strong></em> 结尾</td><td>MetalinkDownloader</td></tr><tr><td>其他</td><td>回退到 HTTPDownloader</td></tr></tbody></table><hr><p><strong>下一步</strong>:</p><ul><li><a href="/TTHSD/zh/guide/getting-started.html">快速开始</a> - 各协议的实际测试用例</li><li><a href="/TTHSD/zh/api/API-overview.html">API 详解</a> - 了解如何调用下载器</li></ul>`,68)])])}const c=s(a,[["render",o]]);export{m as __pageData,c as default};
